#!/bin/bash
set -e
cd ~/acentoza.com
echo "=== writing files ==="
mkdir -p "$(dirname 'app/Helpers/functions.php')"
base64 -d > 'app/Helpers/functions.php' <<'B64END'

B64END
echo "  wrote app/Helpers/functions.php ($(wc -c < 'app/Helpers/functions.php') bytes)"
mkdir -p "$(dirname 'app/Controllers/PublicController.php')"
base64 -d > 'app/Controllers/PublicController.php' <<'B64END'

B64END
echo "  wrote app/Controllers/PublicController.php ($(wc -c < 'app/Controllers/PublicController.php') bytes)"
mkdir -p "$(dirname 'app/Controllers/AuthController.php')"
base64 -d > 'app/Controllers/AuthController.php' <<'B64END'

B64END
echo "  wrote app/Controllers/AuthController.php ($(wc -c < 'app/Controllers/AuthController.php') bytes)"
mkdir -p "$(dirname 'app/Models/Tenant.php')"
base64 -d > 'app/Models/Tenant.php' <<'B64END'

B64END
echo "  wrote app/Models/Tenant.php ($(wc -c < 'app/Models/Tenant.php') bytes)"
mkdir -p "$(dirname 'config/routes.php')"
base64 -d > 'config/routes.php' <<'B64END'

B64END
echo "  wrote config/routes.php ($(wc -c < 'config/routes.php') bytes)"
mkdir -p "$(dirname 'config/sidebar.php')"
base64 -d > 'config/sidebar.php' <<'B64END'

B64END
echo "  wrote config/sidebar.php ($(wc -c < 'config/sidebar.php') bytes)"
mkdir -p "$(dirname 'public/css/app.css')"
base64 -d > 'public/css/app.css' <<'B64END'

B64END
echo "  wrote public/css/app.css ($(wc -c < 'public/css/app.css') bytes)"
mkdir -p "$(dirname 'docs/opsone-brand-direction.md')"
base64 -d > 'docs/opsone-brand-direction.md' <<'B64END'

B64END
echo "  wrote docs/opsone-brand-direction.md ($(wc -c < 'docs/opsone-brand-direction.md') bytes)"
mkdir -p "$(dirname 'database/migrations/048_tenant_slug.sql')"
base64 -d > 'database/migrations/048_tenant_slug.sql' <<'B64END'

B64END
echo "  wrote database/migrations/048_tenant_slug.sql ($(wc -c < 'database/migrations/048_tenant_slug.sql') bytes)"
mkdir -p "$(dirname 'database/migrations/048_tenant_slug_sqlite.sql')"
base64 -d > 'database/migrations/048_tenant_slug_sqlite.sql' <<'B64END'

B64END
echo "  wrote database/migrations/048_tenant_slug_sqlite.sql ($(wc -c < 'database/migrations/048_tenant_slug_sqlite.sql') bytes)"
echo "=== done. clearing PHP opcache ==="
find ~/acentoza.com -name "*.opcache" -delete 2>/dev/null || true
echo "DEPLOY_OK"
